export function getDevotional(day: number): Devotional | undefined {
  if (day < 1 || day > 365) {
    return undefined;
  }
  return devotionalsData[day - 1];
}

export function getAllDevotionals(): Devotional[] {
  return devotionalsData;
}

export default devotionalsData;
